use std::collections::HashMap;
use std::sync::Mutex;

struct Cache<K, V> {
    map: Mutex<HashMap<K, V>>
}

impl<K: std::hash::Hash + Eq, V: Clone> Cache<K, V> {
    fn new() -> Self {
        Cache { map: Mutex::new(HashMap::new()) }
    }

    fn get_or_compute(&self, key: K, compute_fn: impl FnOnce() -> V) -> V {
        let mut map = self.map.lock().unwrap();
        if let Some(result) = map.get(&key).cloned() {
            return result;
        }

        let result = compute_fn();
        map.insert(key, result.clone());
        result
    }
}

use std::collections::HashMap;
use std::sync::Mutex;

struct CacheFn<T, F> where F: Fn(T) -> T + 'static {
    cache: Mutex<HashMap<T, T>>,
    func: F,
} 

impl<T, F> CacheFn<T, F>
where
    T: std::hash::Hash + Eq + std::fmt::Debug + Clone,
    F: Fn(T) -> T + 'static,
{
    fn new(func: F) -> Self {
        CacheFn { 
            cache: Mutex::new(HashMap::new()),
            func,
        }
    }

    fn memoize(&self, input: T) -> T {
        let mut cache = self.cache.lock().unwrap();
        if let Some(result) = cache.get(&input).cloned() {
            println!("Cache hit for {:?}", input);
            return result;
        }

        println!("Cache miss, computing for {:?}", input);
        let result = (self.func)(input.clone());
        cache.insert(input.clone(), result.clone());
        result
    }
}

use std::collections::HashMap;

struct Memoizer<F: Fn(i32, i32) -> f64 + 'static> {
    cache: HashMap<(i32, i32), f64>,
    func: F,
}

impl<F> Memoizer<F> where F: Fn(i32, i32) -> f64 + 'static {
    fn new(func: F) -> Self {
        Memoizer { cache: HashMap::new(), func }
    }

    fn call(&mut self, a: i32, b: i32) -> f64 {
        if let Some(&result) = self.cache.get(&(a, b)) {
            println!("Cache hit for ({}, {}).", a, b);
            return result;
        }

        println!("Cache miss for ({}, {}). Calculating...", a, b);
        let result = (self.func)(a, b);
        self.cache.insert((a, b), result);
        result
    }
}

use std::collections::HashMap;

struct Memoizer<F: Fn(i32) -> i32 + 'static> {
    cache: HashMap<i32, i32>,
    fn_to_call: F,
}

impl<F: Fn(i32) -> i32 + 'static> Memoizer<F> {
    fn new(f: F) -> Self {
        Memoizer { 
            cache: HashMap::new(), 
            fn_to_call: f,
        }
    }

    fn memoize(&mut self, input: i32) -> i32 {
        if let Some(&result) = self.cache.get(&input) {
            println!("Cache hit for {}", input);
            return result;
        }

        println!("Cache miss for {}. Calculating...", input);
        let result = (self.fn_to_call)(input);
        self.cache.insert(input, result);
        result
    }
}

use std::collections::HashMap;
use std::sync::Mutex;

struct CacheMemoizer<F> where F: Fn() -> i32 + 'static {
    cache: Mutex<HashMap<String, i32>>,
    original_fn: F,
}

impl<F> CacheMemoizer<F> where F: Fn() -> i32 + 'static {
    fn new(original_fn: F) -> Self {
        CacheMemoizer { 
            cache: Mutex::new(HashMap::new()),
            original_fn,
        }
    }

    fn compute(&self, key: &str) -> i32 {
        { 
            let mut cache = self.cache.lock().unwrap();
            if let Some(&value) = cache.get(key) {
                return value;
            }
        }

        let result = (self.original_fn)();

        { 
            let mut cache = self.cache.lock().unwrap();
            cache.insert(key.to_string(), result);
        }

        result
    }
}

